☀️ HDR Competitive ProfileUses Windows Auto HDR to push OLED brightness, but keeps the game engine completely stripped of shadows and bloom to prevent blinding double-exposure.Manual Checklist (Do this once)Windows OS: Settings > Display > Use HDR: ON AND Auto HDR: ON.Windows OS: Run the Windows HDR Calibration app (from MS Store) to set peak clipping correctly.Windows OS: Settings > Gaming > Game Mode: ON.Windows OS: Settings > Display > Graphics > Hardware-Accelerated GPU Scheduling: ON.Monitor (ASUS): OSD > Image > Uniform Brightness > OFF (Let HDR manage local dimming).NVCP (3D Settings): Max Frame Rate: 237 FPS | Vertical Sync: ON.NVCP (Display): G-Sync: ON for Fullscreen | Change Resolution: 10 bpc / RGB / Full.Deployment Script (Apply-HDR-Comp.ps1)Deploys the low-clutter engine config so Auto HDR has a clean slate to tone-map.Write-Host "Deploying HDR Competitive Profile (File-Level Only)..." -ForegroundColor Yellow$vPath = "$env:USERPROFILE\Saved Games\Respawn\Apex\local\videoconfig.txt"$aPath = "C:\Program Files (x86)\Steam\steamapps\common\Apex Legends\cfg\autoexec.cfg"$video = @""VideoConfig"{"setting.cl_gib_allow" "0""setting.cl_particle_fallback_base" "0""setting.cl_particle_fallback_multiplier" "1""setting.cl_ragdoll_maxcount" "0""setting.cl_ragdoll_self_collision" "0""setting.mat_forceaniso" "16""setting.mat_mip_linear" "1""setting.stream_memory" "8388608""setting.mat_picmip" "1""setting.particle_cpu_level" "0""setting.r_createmodeldecals" "0""setting.r_decals" "0""setting.r_lod_switch_scale" "2""setting.shadow_enable" "0""setting.shadow_depth_dimen_min" "0""setting.shadow_depth_upres_factor_max" "0""setting.shadow_maxdynamic" "0""setting.dvs_enable" "0""setting.dvs_gpuframetime_min" "15000""setting.dvs_gpuframetime_max" "16500""setting.sound_volume" "1.000000""setting.last_display_width" "2560""setting.last_display_height" "1440""setting.nowindowborder" "0""setting.fullscreen" "1""setting.defaultres" "2560""setting.defaultresheight" "1440""setting.volumetric_lighting" "0""setting.volumetric_fog" "0""setting.mat_vsync_mode" "0""setting.mat_backbuffer_count" "1""setting.mat_antialias_mode" "12""setting.csm_enabled" "0""setting.csm_coverage" "0""setting.csm_cascade_res" "0""setting.fadeDistScale" "1.000000""setting.new_shadow_settings" "0""setting.dynamic_streaming_budget" "0""setting.gamma" "1.006032""setting.configversion" "10""setting.map_detail_level" "2""setting.ssao_quality" "0""setting.mat_disable_bloom" "1""setting.reflex_mode" "2"}"@$autoexec = @"m_rawinput "1"m_customaccel "0"cl_updaterate "60"cl_interp_ratio "2"cl_interp "0"hud_setting_minimapRotate "1"player_setting_enable_fovSlider "1"fov_desired "110""@if(Test-Path $vPath){ Set-ItemProperty -Path $vPath -Name IsReadOnly -Value $false }Set-Content -Path $vPath -Value $video -Encoding UTF8Set-ItemProperty -Path $vPath -Name IsReadOnly -Value $trueif(Test-Path $(Split-Path $aPath)){ Set-Content -Path $aPath -Value $autoexec -Encoding UTF8 }Write-Host "HDR Comp deployed and locked." -ForegroundColor GreenWrite-Host "Ensure Windows HDR & Auto HDR are ON in Windows Settings before launching." -ForegroundColor YellowStart-Sleep -s 4